// Filter statewide AZ511 events down to the Verde Valley box and shape
// them for the site. Sedona sits at 34.8697, -111.761.
const items = $input.all().map(i => i.json);
let evs = [];
if (items.length && Array.isArray(items[0])) evs = items[0];
else if (items.length > 1 || (items[0] && items[0].ID != null)) evs = items.filter(e => e && e.ID != null);
if (!evs.length && items[0] && Array.isArray(items[0].data)) evs = items[0].data;
if (!evs.length && !(items[0] && items[0].ID != null) && !Array.isArray(items[0])) {
  return [{ json: { ok: false, error: 'az511 fetch failed' } }];
}
const B = { latMin: 34.35, latMax: 35.35, lonMin: -112.35, lonMax: -111.35 };
const SED = [34.8697, -111.761];
function mi(la, lo) {
  const dx = (lo - SED[1]) * Math.cos(SED[0] * Math.PI / 180), dy = la - SED[0];
  return Math.round(Math.sqrt(dx * dx + dy * dy) * 69);
}
const out = evs
  .filter(e => e.Latitude >= B.latMin && e.Latitude <= B.latMax && e.Longitude >= B.lonMin && e.Longitude <= B.lonMax)
  .map(e => ({
    id: e.ID,
    type: e.EventType || '',
    sub: e.EventSubType || '',
    road: e.RoadwayName || '',
    dir: e.DirectionOfTravel && e.DirectionOfTravel !== 'None' ? e.DirectionOfTravel : '',
    desc: String(e.Description || '').slice(0, 240),
    full: !!e.IsFullClosure,
    lanes: e.LanesAffected || '',
    lat: e.Latitude, lon: e.Longitude,
    mi: mi(e.Latitude, e.Longitude),
    updated: e.LastUpdated || e.Reported || null
  }))
  .sort((a, b) => a.mi - b.mi)
  .slice(0, 30);
return [{ json: { ok: true, at: new Date().toISOString(), events: out } }];
